import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const coreRoot = path.resolve(__dirname, "..");
const targetRoot = path.resolve(process.argv[2] || process.env.PROJECT_ROOT || process.cwd());

function ensureDir(dirPath) {
  fs.mkdirSync(dirPath, { recursive: true });
}

function copyFile(src, dest) {
  ensureDir(path.dirname(dest));
  fs.copyFileSync(src, dest);
}

function readJson(filePath) {
  return JSON.parse(fs.readFileSync(filePath, "utf8"));
}

function writeJson(filePath, data) {
  fs.writeFileSync(filePath, `${JSON.stringify(data, null, 2)}\n`, "utf8");
}

const ciTemplate = path.join(coreRoot, "templates", "ci.yml");
const releaseTemplate = path.join(coreRoot, "templates", "release.yml");
const codexAgents = path.join(coreRoot, "codex", "AGENTS.md");
const codexConfig = path.join(coreRoot, "codex", "config.toml");
const preCommitCheck = path.join(coreRoot, "scripts", "pre-commit-check.sh");

copyFile(ciTemplate, path.join(targetRoot, ".github", "workflows", "ci.yml"));
copyFile(releaseTemplate, path.join(targetRoot, ".github", "workflows", "release.yml"));
copyFile(codexAgents, path.join(targetRoot, ".codex", "AGENTS.md"));
copyFile(codexConfig, path.join(targetRoot, ".codex", "config.toml"));
copyFile(preCommitCheck, path.join(targetRoot, "scripts", "pre-commit-check.sh"));
fs.chmodSync(path.join(targetRoot, "scripts", "pre-commit-check.sh"), 0o755);

const packageJsonPath = path.join(targetRoot, "package.json");
if (!fs.existsSync(packageJsonPath)) {
  throw new Error(`No package.json found in target root: ${targetRoot}`);
}

const pkg = readJson(packageJsonPath);
pkg.scripts = pkg.scripts || {};
pkg.scripts.validate = "bash scripts/pre-commit-check.sh";
pkg.scripts.gate = "node node_modules/release-governance-core/scripts/release-gate.mjs";
pkg.scripts["gate:json"] = "node node_modules/release-governance-core/scripts/release-gate.mjs --json";
pkg.scripts["release:dry-run"] = "node node_modules/release-governance-core/scripts/release.mjs --dry-run";

writeJson(packageJsonPath, pkg);

console.log(`Installed release-governance-core into: ${targetRoot}`);
console.log("Updated workflows, codex policy files, scripts/pre-commit-check.sh, and package.json scripts.");
